function UIBaseCtrl:_InnerUpdateUiShow()
    local isShow = self._isUiShow and self._loadFinish

    local canvasGroup = self._panelCanvasGroup
    if canvasGroup then
        canvasGroup.alpha = isShow and 1 or 0
        canvasGroup.interactable = isShow
    end

    if IsValid(self._panelCanvas)  then
        self._panelCanvas.enabled = isShow
    end

    if IsValid(self._panelRayCaster)  then
        self._panelRayCaster.enabled = isShow
    end
end

function UIBaseCtrl:InternalSetUiLayer()
    local canvas = self._panelCanvas
    if not IsNull(canvas) then
        canvas.sortingLayerName = self:GetUiLayerName()
    end
end

function UIBaseCtrl:InternalSetUiOrder()
    if not self._uiLayerOrder then return end
    local canvas = self._panelCanvas
    if not IsNull(canvas) then
        local oldOrder = canvas.sortingOrder
        local newOrder = self._uiLayerOrder
        canvas.sortingOrder = newOrder
        LxUiHelper.UpdateUIOrder(canvas,newOrder - oldOrder)
    end

    self:ExtendSetUiOrder()

    if not self:IsChildCtrl() then
        for k,childCtrl in pairs(self._childCtrls) do
            childCtrl:ExtendSetUiOrder()
        end
    end
end

function UIBaseCtrl:SetLayout()
