function UIBaseCtrl:SetNotch(notchEnable, min, max)
    if not min or not max then return end

    local rect = self._panelRootTrans
    if IsNull(rect) then return end
    local notchType = self._notchType
    if notchType == UINotchType.Full then
        rect.anchorMin = Vector2(min.x, min.y)
        rect.anchorMax = Vector2(max.x, max.y)
    elseif notchType == UINotchType.Landscape then
        rect.anchorMin = Vector2(min.x, 0)
        rect.anchorMax = Vector2(max.x, 1)
    end

    if not self:IsChildCtrl() and self._isChildNotch then
        for k, v in pairs(self._childCtrls) do
            v:SetNotch(notchEnable, min, max)
        end
    end
end

function UIBaseCtrl:CloseUI()
