---@region binder
function UIBaseCtrl:InitUIBinder()
    if self:IsNullPanel() then
        return
    end
    self._mPrefabVars = {}
    local prefabVar = self.gameObject:GetComponent(typeOfPrefabVar)
    if not IsNull(prefabVar) then
        local varData = prefabVar:GetVarArray()
        local iter = varData:GetEnumerator()
        while iter:MoveNext() do
            local varObj = iter.Current
            if not IsNull(varObj) then
                table.insert(self._mPrefabVars, varObj.name)
                --lua访问C#时候，c#对象会转成实际类型
                --table的key的访问有两种方式，得以实现如此
                self[varObj.name] = varObj.objValue
            end
        end

        local spriteName
        local atlasName
        local loadAtlas = {}
        local loadAtlasMap = {}
        local initSetImageList = {}
        local varAtlas = prefabVar:GetVarAtlasList()
        local varAtlasIter = varAtlas:GetEnumerator()
        while varAtlasIter:MoveNext() do
            local data = varAtlasIter.Current
            if data then
                spriteName = data.atlasName
                if string.isvalid(spriteName) then
                    table.insert(initSetImageList,{
                        atlasName = spriteName,
                        img = data.img
                    })
                    local lngSpriteName = LxResPathUtil.GetLngSpriteName(spriteName)
                    atlasName = LxResPathUtil.GetSpriteAtlasPathBySpriteName(lngSpriteName)
                    if not loadAtlasMap[atlasName] and atlasName then
                        table.insert(loadAtlas, atlasName)
                        loadAtlasMap[atlasName] = true
                    end
                end
            end
        end
        self._mInnerVarAtlasList = initSetImageList

        --local atlas = prefabVar:GetAtlasList()
        --local atlasIter = atlas:GetEnumerator()
        --while atlasIter:MoveNext() do
        --    local atlasName = atlasIter.Current
        --    if string.isvalid(atlasName) then
        --        table.insert(loadAtlas, atlasName)
        --    end
        --end
        --- 加载
        if #loadAtlas > 0 then
            self._mInnerAtlasNames = loadAtlas
        end
    end
end

function UIBaseCtrl:ClearAtlasPreLoadTask()
    if self._atlasLoadTask then
        self._atlasLoadTask:Dispose()
        self._atlasLoadTask = nil
    end
end

function UIBaseCtrl:_InnerOnAtlasPreloadTaskFinished()
    local initSetImageList = self._mInnerVarAtlasList
    for i,v in ipairs(initSetImageList) do
        self:SetImage(v.img,v.atlasName)
    end

    self._loadFinish = true
    self:_InnerUpdateUiShow()
    self:CheckIsNeedDoStart()
end

local _BuiltinDefaultName = "Builtin/builtin_ui_default"
function UIBaseCtrl:StartAtlasPreloadTask()
    self:ClearAtlasPreLoadTask()

    if not self._mInnerAtlasNames then
        self:_InnerOnAtlasPreloadTaskFinished()
        return
    end

    local task = require("app.component.task.LxAtlasLoadTask"):new()
    self._atlasLoadTask = task
    task:Initialize()
    task:InitTask(self._InnerOnAtlasPreloadTaskFinished, nil, self)

    if LOG_INFO_ENABLED then
        printInfo("UI", "%s 预设图集数量 ： %s", self:GetUiName(), #self._mInnerAtlasNames)
    end

    local loadAtlas = self._mInnerAtlasNames
    --local formatStr = "UI/SAtlas/%s.spriteatlasv2"
    for i,v in ipairs(loadAtlas) do
        if (v == _BuiltinDefaultName) then
            task:AddData(v)
        else
            --task:AddData(string.format(formatStr, v))
            task:AddData(v)
        end

    end
    task:StartTask()
end

function UIBaseCtrl:CheckIsNeedDoStart()
    if not self._isStarting then return end
    self:DoStart()
end

function UIBaseCtrl:ClearUIBinder()
    if self._mPrefabVars ~= nil then
        for _, value in ipairs(self._mPrefabVars) do
            self[value] = nil
        end
        self._mPrefabVars = nil
    end

    if self._mInnerVarAtlasList ~= nil then
        for _, value in ipairs(self._mInnerVarAtlasList) do
            value.img = nil
        end
        self._mInnerVarAtlasList = nil
    end
end
