---@region 界面动画
function UIBaseCtrl:_InternalSetUiAnimation()
    if self._uiAnimationType == UIAnimationType.None or not self._isUiShow then
        self:OnUiAnimationEnd()
        return
    end

    self:ClearUIAnimation()
    self._uiAnimation = require("app.ui.item.LxUiAnimation"):new()
    self._uiAnimation:Initialize(self, self.OnUiAnimationEnd, self._uiAnimationType)
    self._isAnimationPlaying = true
    self._uiAnimation:StartAnimation()
end

function UIBaseCtrl:SetUiAnimationType(uiAniType)
    self._uiAnimationType = uiAniType
end

function UIBaseCtrl:AbortAnimation()
    if not self._isAnimationPlaying then
        return
    end
    self._uiAnimation:OnAnimationEnd()
end

function UIBaseCtrl:ClearUIAnimation()
    if self._uiAnimation then
        self._uiAnimation:Dispose()
        self._uiAnimation = nil
    end
end

function UIBaseCtrl:OnUiAnimationEnd()
    self._isAnimationPlaying = false
    self:ChangeToGuideReady()
    self:NotifyCreated()
    self:NotifyUiAnimationEnd()
end

function UIBaseCtrl:NotifyUiAnimationEnd()

end

function UIBaseCtrl:IsAnimationPlaying()
    return self._isAnimationPlaying
end
