    if ctrl then
        self._childCtrls[uiKey] = nil
        local gameObject = ctrl.gameObject
        ctrl:Dispose()
        local panelMgr = MgrCenter.PanelMgr
        if panelMgr then
            panelMgr:CloseChildPanel(uiKey, gameObject)
        end
    end
end

